-- Tab System Functions
local function Tab_Main window_SetVisible(visible)
    if Main window then Main window.Visible = visible end
    if Title then
        Title.Visible = visible
    end
    if Title Background then
        Title Background.Visible = visible
    end
    if Pickaxe then
        Pickaxe.Visible = visible
    end
    if Pickaxe Selection then
        Pickaxe Selection.Visible = visible
        if Pickaxe Selection_Text then Pickaxe Selection_Text.Visible = visible end
        if Pickaxe Selection_Arrow then Pickaxe Selection_Arrow.Visible = visible end
        if not visible then
            for _, item in ipairs(Pickaxe Selection_Items) do
                item.Box.Visible = false
                item.Text.Visible = false
            end
        end
    end
    if Minimum value then
        Minimum value.Visible = visible
    end
    if Minimum Value Selection then
        Minimum Value Selection.Visible = visible
        if Minimum Value Selection_Knob then Minimum Value Selection_Knob.Visible = visible end
        if Minimum Value Selection_ValueText then Minimum Value Selection_ValueText.Visible = visible end
    end
    if Message then
        Message.Visible = visible
    end
    if Message2 then
        Message2.Visible = visible
    end
    if Render Distance then
        Render Distance.Visible = visible
    end
    if Render Distance Selection then
        Render Distance Selection.Visible = visible
        if Render Distance Selection_Knob then Render Distance Selection_Knob.Visible = visible end
        if Render Distance Selection_ValueText then Render Distance Selection_ValueText.Visible = visible end
    end
    if Teleports then
        Teleports.Visible = visible
    end
    if Plot Teleport then
        Plot Teleport.Visible = visible
        if Plot Teleport_Text then Plot Teleport_Text.Visible = visible end
    end
    if Shop Teleport then
        Shop Teleport.Visible = visible
        if Shop Teleport_Text then Shop Teleport_Text.Visible = visible end
    end
    if Mine Teleport then
        Mine Teleport.Visible = visible
        if Mine Teleport_Text then Mine Teleport_Text.Visible = visible end
    end
    if Hide The Ui then
        Hide The Ui.Visible = visible
    end
    if Keybind To Hide then
        Keybind To Hide.Visible = visible
        if Keybind To Hide_Text then Keybind To Hide_Text.Visible = visible end
    end
end

