-- Funciones de Teletransporte
local lp = game:GetService("Players").LocalPlayer
local workspace = game:GetService("Workspace")

local function teleportTo(targetPos)
    local char = lp.Character
    if char then
        local hrp = char:FindFirstChild("HumanoidRootPart")
        if hrp then
            hrp.Position = targetPos
        end
    end
end

local function teleportToPlot()
    local plotId = lp:GetAttribute("PlotId")
    if plotId then
        local plots = workspace:FindFirstChild("Plots")
        if plots then
            local myPlot = plots:FindFirstChild(tostring(plotId))
            if myPlot then
                local centre = myPlot:FindFirstChild("Centre")
                if centre then
                    teleportTo(centre.Position)
                end
            end
        end
    end
end

-- Hilos de ESP
local activeOres = {}
local espCache = {}

-- 1. Escáner de minerales (Se actualiza cada segundo para no causar lag)
task.spawn(function()
    while true do
        local folder = workspace:FindFirstChild("PlacedOre")
        local char = lp.Character
        if folder and char and char:FindFirstChild("HumanoidRootPart") then
            local myPos = char:FindFirstChild("HumanoidRootPart").Position
            
            -- Leer los valores actuales directamente de tu UI
            local currentPick = Pickaxe_Selection_Text.Text
            local strength = picks_strength[currentPick] or 0
            local minPrice = Minimum_Value_Selection_Value
            local maxD = Render_Distance_Selection_Value

            local list = {}
            for _, ore in pairs(folder:GetChildren()) do
                if ore:IsA("MeshPart") then
                    -- Distancia calculada con formula general
                    local dist = math.sqrt((ore.Position.X - myPos.X)^2 + (ore.Position.Y - myPos.Y)^2 + (ore.Position.Z - myPos.Z)^2)
                    
                    if dist <= maxD then
                        local mId = ore:GetAttribute("MineId")
                        if mId and ores_data[mId] then
                            local d = ores_data[mId]
                            -- Filtrar por fuerza del pico y precio minimo de tu slider
                            if strength >= d.r and d.v >= minPrice then
                                table.insert(list, {obj = ore, data = d})
                            end
                        end
                    end
                end
            end
            activeOres = list
        end
        task.wait(1)
    end
end)

-- 2. Renderizador (Dibuja los textos a alta velocidad)
task.spawn(function()
    while true do
        local rendered = {}
        local currentPick = Pickaxe_Selection_Text.Text
        local strength = picks_strength[currentPick] or 0

        for _, item in pairs(activeOres) do
            local obj = item.obj
            local d = item.data

            if obj and obj.Parent then
                local pos, onScreen = WorldToScreen(obj.Position)
                if onScreen then
                    if not espCache[obj] then
                        local txt = Drawing.new("Text")
                        txt.Size = 14
                        txt.Center = true
                        txt.Outline = true
                        txt.Font = 3
                        espCache[obj] = txt
                    end
                    local txt = espCache[obj]
                    txt.Visible = true
                    txt.Position = pos
                    txt.Text = obj:GetAttribute("MineId") .. " [$" .. tostring(d.v) .. "]"

                    -- Sistema de colores original
                    if d.r >= strength * 0.8 then
                        txt.Color = Color3.fromHex("#ff1e1e") -- Rojo
                    else
                        txt.Color = Color3.fromHex("#1eff1e") -- Verde
                    end
                    rendered[obj] = true
                end
            end
        end

        -- Limpieza de textos que ya no deben verse
        for obj, txt in pairs(espCache) do
            if not rendered[obj] then
                txt.Visible = false
                if not obj or not obj.Parent then
                    txt:Remove()
                    espCache[obj] = nil
                end
            end
        end

        task.wait(0.01)
    end
end)

-- Input Handling
local dragging = nil
local dragStart = nil
local startPos = nil
local knobStartPos = nil
local lastMouse1 = false

while true do
    wait(0.01)
    if isrbxactive() then
        local mouse1 = ismouse1pressed()
        local mPos = Vector2.new(Mouse.X, Mouse.Y)

        -- Keybind Listeners
        if Keybind To Hide_IsListening then
             for i = 1, 255 do
                 if iskeypressed(i) and not ismouse1pressed() then -- Avoid mouse clicks registering as keys if shared ID
                     Keybind To Hide_Key = i
                     Keybind To Hide_IsListening = false
                     local keyName = KeyNames[i] or "Unknown"
                     Keybind To Hide_Text.Text = "[ " .. keyName .. " ]"
                     Keybind To Hide_Text.Color = Color3.fromHex("#ffffff")
                     pcall(function() onKeyChanged(i) end)
                     wait(0.2) -- Prevent immediate trigger
                     break
                 end
             end
        else
             if iskeypressed(Keybind To Hide_Key) then
                 -- Intelligent Action
                 local newState = not Main window.Visible
                 Main window.Visible = newState
                 Title.Visible = newState
                 Title Background.Visible = newState
                 Pickaxe Selection.Visible = newState
                 Pickaxe Selection_Text.Visible = newState
                 Pickaxe Selection_Arrow.Visible = newState
                 Pickaxe.Visible = newState
                 Minimum Value Selection.Visible = newState
                 Minimum Value Selection_Knob.Visible = newState
                 Minimum Value Selection_ValueText.Visible = newState
                 Minimum value.Visible = newState
                 Message.Visible = newState
                 Message2.Visible = newState
                 Render Distance.Visible = newState
                 Render Distance Selection.Visible = newState
                 Render Distance Selection_Knob.Visible = newState
                 Render Distance Selection_ValueText.Visible = newState
                 Plot Teleport.Visible = newState
                 Plot Teleport_Text.Visible = newState
                 Shop Teleport.Visible = newState
                 Shop Teleport_Text.Visible = newState
                 Mine Teleport.Visible = newState
                 Mine Teleport_Text.Visible = newState
                 Teleports.Visible = newState
                 Keybind To Hide.Visible = newState
                 Keybind To Hide_Text.Visible = newState
                 Hide The Ui.Visible = newState
                 wait(0.2) -- Debounce
             end
        end

        -- Mouse Down (Just Pressed)
        if mouse1 and not lastMouse1 then
            -- Button Pickaxe Selection
            if Pickaxe Selection.Visible and mPos.X >= Pickaxe Selection.Position.X and mPos.X <= Pickaxe Selection.Position.X + Pickaxe Selection.Size.X and
               mPos.Y >= Pickaxe Selection.Position.Y and mPos.Y <= Pickaxe Selection.Position.Y + Pickaxe Selection.Size.Y then
                pcall(function() onChanged() end)
                -- Toggle Dropdown
                local isOpen = Pickaxe Selection_Items[1].Box.Visible
                for _, item in ipairs(Pickaxe Selection_Items) do
                    item.Box.Visible = not isOpen
                    item.Text.Visible = not isOpen
                end
            end
            -- Dropdown Items for Pickaxe Selection
            if Pickaxe Selection_Items[1].Box.Visible then
                for _, item in ipairs(Pickaxe Selection_Items) do
                    if mPos.X >= item.Box.Position.X and mPos.X <= item.Box.Position.X + item.Box.Size.X and
                       mPos.Y >= item.Box.Position.Y and mPos.Y <= item.Box.Position.Y + item.Box.Size.Y then
                        Pickaxe Selection_Text.Text = item.Value
                        -- Close Dropdown
                        for _, it in ipairs(Pickaxe Selection_Items) do
                            it.Box.Visible = false
                            it.Text.Visible = false
                        end
                        if onChanged then pcall(function() onChanged(item.Value) end) end
                    end
                end
            end
-- ==========================================================
-- SECCIÓN DE DETECCIÓN DE CLICS (Dentro del while true do)
-- ==========================================================

-- 1. Botón para ir al Plot (Tu Parcela)
if Plot_Teleport.Visible and mPos.X >= Plot_Teleport.Position.X and mPos.X <= Plot_Teleport.Position.X + Plot_Teleport.Size.X and mPos.Y >= Plot_Teleport.Position.Y and mPos.Y <= Plot_Teleport.Position.Y + Plot_Teleport.Size.Y then
    pcall(function() 
        teleportToPlot() -- Esta función busca tu PlotId automáticamente
    end)
end

-- 2. Botón para ir a la Tienda (Shop)
if Shop_Teleport.Visible and mPos.X >= Shop_Teleport.Position.X and mPos.X <= Shop_Teleport.Position.X + Shop_Teleport.Size.X and mPos.Y >= Shop_Teleport.Position.Y and mPos.Y <= Shop_Teleport.Position.Y + Shop_Teleport.Size.Y then
    pcall(function() 
        teleportTo(Vector3.new(-1550, 10, 20)) 
    end)
end

-- 3. Botón para ir a la Mina (Mine)
if Mine_Teleport.Visible and mPos.X >= Mine_Teleport.Position.X and mPos.X <= Mine_Teleport.Position.X + Mine_Teleport.Size.X and mPos.Y >= Mine_Teleport.Position.Y and mPos.Y <= Mine_Teleport.Position.Y + Mine_Teleport.Size.Y then
    pcall(function() 
        teleportTo(Vector3.new(-1889, 7, -193)) 
    end)
end
            -- Button Keybind To Hide
            if Keybind To Hide.Visible and mPos.X >= Keybind To Hide.Position.X and mPos.X <= Keybind To Hide.Position.X + Keybind To Hide.Size.X and
               mPos.Y >= Keybind To Hide.Position.Y and mPos.Y <= Keybind To Hide.Position.Y + Keybind To Hide.Size.Y then
                pcall(function() onKeyChanged() end)
                -- Keybind Click
                Keybind To Hide_IsListening = true
                Keybind To Hide_Text.Text = "..."
                Keybind To Hide_Text.Color = Color3.fromHex("#FFFF00")
            end
            -- Drag Main window
            if Main window.Visible and mPos.X >= Main window.Position.X and mPos.X <= Main window.Position.X + Main window.Size.X and
               mPos.Y >= Main window.Position.Y and mPos.Y <= Main window.Position.Y + Main window.Size.Y then
                dragging = Main window
                dragStart = mPos
                startPos = Main window.Position
            end
            -- Drag Minimum Value Selection
            if Minimum Value Selection_Knob.Visible and mPos.X >= Minimum Value Selection_Knob.Position.X and mPos.X <= Minimum Value Selection_Knob.Position.X + Minimum Value Selection_Knob.Size.X and
               mPos.Y >= Minimum Value Selection_Knob.Position.Y and mPos.Y <= Minimum Value Selection_Knob.Position.Y + Minimum Value Selection_Knob.Size.Y then
                dragging = Minimum Value Selection_Knob
                dragStart = mPos
                startPos = Minimum Value Selection_Knob.Position
            end
            -- Drag Render Distance Selection
            if Render Distance Selection_Knob.Visible and mPos.X >= Render Distance Selection_Knob.Position.X and mPos.X <= Render Distance Selection_Knob.Position.X + Render Distance Selection_Knob.Size.X and
               mPos.Y >= Render Distance Selection_Knob.Position.Y and mPos.Y <= Render Distance Selection_Knob.Position.Y + Render Distance Selection_Knob.Size.Y then
                dragging = Render Distance Selection_Knob
                dragStart = mPos
                startPos = Render Distance Selection_Knob.Position
            end
        end

        -- Mouse Up (Just Released)
        if not mouse1 and lastMouse1 then
            dragging = nil
        end

        -- Dragging Update
        if dragging and mouse1 then
            local delta = mPos - dragStart
            dragging.Position = startPos + delta
            if dragging == Minimum Value Selection_Knob then
                -- Constrain to track
                local minX = Minimum Value Selection.Position.X
                local maxX = Minimum Value Selection.Position.X + Minimum Value Selection.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Minimum Value Selection.Position.Y + 5 - dragging.Size.Y/2)
                -- Calculate Value
                local percent = (dragging.Position.X - minX) / (Minimum Value Selection.Size.X)
                local value = 0 + (15000 - 0) * percent
                Minimum Value Selection_Value = value
                Minimum Value Selection_ValueText.Text = tostring(math.floor(value)) .. "$"
                pcall(function() onChanged(value) end)
            end
            if dragging == Render Distance Selection_Knob then
                -- Constrain to track
                local minX = Render Distance Selection.Position.X
                local maxX = Render Distance Selection.Position.X + Render Distance Selection.Size.X
                if dragging.Position.X < minX then dragging.Position = Vector2.new(minX, dragging.Position.Y) end
                if dragging.Position.X > maxX then dragging.Position = Vector2.new(maxX, dragging.Position.Y) end
                dragging.Position = Vector2.new(dragging.Position.X, Render Distance Selection.Position.Y + 5 - dragging.Size.Y/2)
                -- Calculate Value
                local percent = (dragging.Position.X - minX) / (Render Distance Selection.Size.X)
                local value = 0 + (30000 - 0) * percent
                Render Distance Selection_Value = value
                Render Distance Selection_ValueText.Text = tostring(math.floor(value)) .. ""
                pcall(function() onChanged(value) end)
            end
            if dragging == Main window then
                Title.Position = dragging.Position + Vector2.new(94, 0)
                Title Background.Position = dragging.Position + Vector2.new(0, 0)
                Pickaxe.Position = dragging.Position + Vector2.new(38, 45)
                Pickaxe Selection.Position = dragging.Position + Vector2.new(8, 67)
                Pickaxe Selection_Text.Position = Pickaxe Selection.Position + Vector2.new(5, 2.5)
                Pickaxe Selection_Arrow.Position = Pickaxe Selection.Position + Vector2.new(134 - 20, 2.5)
                for i, item in ipairs(Pickaxe Selection_Items) do
                    item.Box.Position = Pickaxe Selection.Position + Vector2.new(0, 24 * i)
                    item.Text.Position = item.Box.Position + Vector2.new(5, 2.5)
                end
                Minimum value.Position = dragging.Position + Vector2.new(179, 115)
                Minimum Value Selection.Position = dragging.Position + Vector2.new(21.5, 162)
                local percent = (Minimum Value Selection_Value - 0) / (15000 - 0)
                Minimum Value Selection_Knob.Position = Minimum Value Selection.Position + Vector2.new(464 * percent - 10, 5 - 10)
                Minimum Value Selection_ValueText.Position = Minimum Value Selection.Position + Vector2.new(464/2, -10)
                Message.Position = dragging.Position + Vector2.new(251, 179)
                Message2.Position = dragging.Position + Vector2.new(46, 202)
                Render Distance.Position = dragging.Position + Vector2.new(151, 226)
                Render Distance Selection.Position = dragging.Position + Vector2.new(21.5, 267)
                local percent = (Render Distance Selection_Value - 0) / (30000 - 0)
                Render Distance Selection_Knob.Position = Render Distance Selection.Position + Vector2.new(464 * percent - 10, 5 - 10)
                Render Distance Selection_ValueText.Position = Render Distance Selection.Position + Vector2.new(464/2, -10)
                Teleports.Position = dragging.Position + Vector2.new(302, 45)
                Plot Teleport.Position = dragging.Position + Vector2.new(180, 68.5)
                Plot Teleport_Text.Position = Plot Teleport.Position + Vector2.new(104/2, 21/2)
                Shop Teleport.Position = dragging.Position + Vector2.new(396, 68.5)
                Shop Teleport_Text.Position = Shop Teleport.Position + Vector2.new(104/2, 21/2)
                Mine Teleport.Position = dragging.Position + Vector2.new(288, 68.5)
                Mine Teleport_Text.Position = Mine Teleport.Position + Vector2.new(104/2, 21/2)
                Hide The Ui.Position = dragging.Position + Vector2.new(187, 285)
                Keybind To Hide.Position = dragging.Position + Vector2.new(186.5, 309)
                Keybind To Hide_Text.Position = Keybind To Hide.Position + Vector2.new(134/2, 14/2)
            end
        end

        lastMouse1 = mouse1
    end
